# Exploratory: 2D unstructured quadrilateral mesh on [−1, 1]² with the
# resolution at the centre 10× higher than at the boundary, generated by
# Gmsh with a radial mesh-size field. The Frontal-Delaunay-for-quads
# algorithm plus blossom recombination produce cells whose aspect ratio
# stays near 1 everywhere — only the *size* varies with position.
#
# This is the unstructured counterpart of `meshplot2d.jl` (tensor-product
# stretching), which suffered from highly anisotropic cells near the edge
# midpoints because a global axis-aligned stretching cannot deliver
# isotropic refinement.

using CairoMakie
using Gmsh: gmsh
using SixelTerm

# ----- parameters ----------------------------------------------------------

L        = 1.0          # half-width of the square: domain is [−L, L]²
h_center = 0.025        # target cell size at the origin
h_edge   = 0.25         # target cell size on the outer boundary  (ratio 10)

# ----- Gmsh model ----------------------------------------------------------

gmsh.initialize()
try
    gmsh.option.setNumber("General.Terminal", 0)
    gmsh.clear()
    gmsh.model.add("square")

    # Four corners + four edges + one plane surface.
    p1 = gmsh.model.geo.addPoint(-L, -L, 0, h_edge)
    p2 = gmsh.model.geo.addPoint( L, -L, 0, h_edge)
    p3 = gmsh.model.geo.addPoint( L,  L, 0, h_edge)
    p4 = gmsh.model.geo.addPoint(-L,  L, 0, h_edge)
    l1 = gmsh.model.geo.addLine(p1, p2)
    l2 = gmsh.model.geo.addLine(p2, p3)
    l3 = gmsh.model.geo.addLine(p3, p4)
    l4 = gmsh.model.geo.addLine(p4, p1)
    cl = gmsh.model.geo.addCurveLoop([l1, l2, l3, l4])
    ps = gmsh.model.geo.addPlaneSurface([cl])
    gmsh.model.geo.synchronize()

    # Mesh-size field: linear interpolation along the L^∞ "distance from
    # the origin" (= max(|x|, |y|), which equals 1 on every face of the
    # unit square). Gives h ≈ h_center at the origin and h ≈ h_edge on
    # the whole outer boundary.
    fld = gmsh.model.mesh.field.add("MathEval")
    gmsh.model.mesh.field.setString(fld, "F",
        "$h_center + ($h_edge - $h_center) * max(abs(x), abs(y))")
    gmsh.model.mesh.field.setAsBackgroundMesh(fld)

    # Suppress Gmsh's default size sources so the field is honoured exactly.
    gmsh.option.setNumber("Mesh.MeshSizeFromPoints",        0)
    gmsh.option.setNumber("Mesh.MeshSizeFromCurvature",     0)
    gmsh.option.setNumber("Mesh.MeshSizeExtendFromBoundary", 0)

    # Frontal-Delaunay for quads + blossom recombination = best-quality
    # unstructured quad mesh.
    gmsh.option.setNumber("Mesh.Algorithm",             8)   # Frontal-Delaunay-quads
    gmsh.option.setNumber("Mesh.RecombineAll",          1)
    gmsh.option.setNumber("Mesh.RecombinationAlgorithm", 1)  # blossom
    gmsh.option.setNumber("Mesh.Smoothing",           100)   # Laplacian smoothing passes

    gmsh.model.mesh.generate(2)
    gmsh.model.mesh.recombine()

    # --- extract nodes and quad connectivity ------------------------------
    global node_tags, coords, _ = gmsh.model.mesh.getNodes()
    global N_nodes  = length(node_tags)
    global xs       = [coords[3i - 2] for i in 1:N_nodes]
    global ys       = [coords[3i - 1] for i in 1:N_nodes]
    tag_to_idx = Dict(node_tags[i] => i for i in 1:N_nodes)

    # 2D elements: we asked for quads (Gmsh type 3).
    types, _, conn = gmsh.model.mesh.getElements(2)
    qi = findfirst(==(3), types)
    qi === nothing && error("no quadrilateral elements were generated")
    quad_nodes = conn[qi]
    global N_quads = length(quad_nodes) ÷ 4
    global quads = [
        ntuple(k -> tag_to_idx[quad_nodes[4(q - 1) + k]], 4) for q in 1:N_quads
    ]
finally
    gmsh.finalize()
end

# ----- sanity check --------------------------------------------------------

# Cell "size" proxy: sqrt of cell area, for each quad.
function quad_area(q)
    (x1, y1) = (xs[q[1]], ys[q[1]])
    (x2, y2) = (xs[q[2]], ys[q[2]])
    (x3, y3) = (xs[q[3]], ys[q[3]])
    (x4, y4) = (xs[q[4]], ys[q[4]])
    # Shoelace formula
    return 0.5 * abs((x1 - x3) * (y2 - y4) + (x4 - x2) * (y1 - y3))
end
sizes = sqrt.(quad_area.(quads))
println("nodes               : $(N_nodes)")
println("quads               : $(N_quads)")
println("min cell size (√A)  : $(round(minimum(sizes), digits=5))")
println("max cell size (√A)  : $(round(maximum(sizes), digits=5))")
println("max/min ratio       : $(round(maximum(sizes)/minimum(sizes), digits=3))")

# ----- plot ----------------------------------------------------------------

fig = Figure(; size=(700, 700))
ax  = Axis(fig[1, 1];
           aspect=DataAspect(),
           title="Unstructured quad mesh ($(N_quads) cells, "*
                 "edge/centre size ratio ≈ $(round(h_edge/h_center, digits=1)))",
           xlabel="x", ylabel="y")

# Draw each quad as a closed polyline.
for q in quads
    px = [xs[q[1]], xs[q[2]], xs[q[3]], xs[q[4]], xs[q[1]]]
    py = [ys[q[1]], ys[q[2]], ys[q[3]], ys[q[4]], ys[q[1]]]
    lines!(ax, px, py; color=(:steelblue, 0.7), linewidth=0.6)
end

# Mark vertices.
scatter!(ax, xs, ys; markersize=2, color=:black)

display(fig)
nothing
